func (a *attacher) stopSpawn(ctx context.Context, spawnID string) {
	a.mu.Lock()
	var ps []*Pump
	for k, p := range a.pumps {
		if k.spawnID == spawnID { ps = append(ps, p); delete(a.pumps, k) }
	}
	var relays []*tmuxRelay
	for k, r := range a.tmuxRelays {
		if k.spawnID == spawnID { relays = append(relays, r); delete(a.tmuxRelays, k) }
	}
	delete(a.sessions, spawnID)
	a.mu.Unlock()
	for _, p := range ps { p.stop() }
	for _, r := range relays { r.stop() }
	if err := a.mgr.Stop(ctx, spawnID); err != nil { logErr("stopSpawn "+spawnID, err) }
	a.mu.Lock()
	if a.active > 0 { a.active-- }
	a.mu.Unlock()
	a.status(spawnID, nodev1.SpawnPhase_STOPPED, "")
}
```
